import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../utils/AuthContext';
import API from '../utils/api';

export default function Register() {
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError(''); setLoading(true);
    try {
      const res = await API.post('/auth/register', form);
      login(res.data.user, res.data.token);
      navigate('/profile');
    } catch (err) {
      setError(err.response?.data?.error || 'Registration failed. Please try again.');
    }
    setLoading(false);
  };

  return (
    <div className="auth-page">
      <div className="auth-left">
        <div style={{ position:'relative', zIndex:1, maxWidth:480 }}>
          <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:48 }}>
            <div style={{ width:44, height:44, background:'linear-gradient(135deg,#6366f1,#8b5cf6)', borderRadius:12, display:'flex', alignItems:'center', justifyContent:'center', fontSize:20 }}>🎯</div>
            <span style={{ fontFamily:'Syne,sans-serif', fontSize:24, fontWeight:800, background:'linear-gradient(135deg,#fff,#818cf8)', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent' }}>PlaceAI</span>
          </div>

          <h1 style={{ fontFamily:'Syne,sans-serif', fontSize:42, fontWeight:800, lineHeight:1.1, marginBottom:20, letterSpacing:'-1px' }}>
            Start your<br />
            <span style={{ background:'linear-gradient(135deg,#6366f1,#22d3ee)', WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent' }}>placement</span><br />
            journey
          </h1>

          <p style={{ color:'var(--text2)', fontSize:16, lineHeight:1.7, marginBottom:40, maxWidth:360 }}>
            Join thousands of students preparing smarter with AI-powered tools.
          </p>

          <div style={{ background:'rgba(99,102,241,0.08)', border:'1px solid rgba(99,102,241,0.15)', borderRadius:14, padding:20 }}>
            <div style={{ fontSize:13, fontWeight:700, color:'var(--indigo2)', marginBottom:12 }}>✨ What you get for free</div>
            {['AI Mock Interviews with instant feedback','Company eligibility matching','Personalized 30-day roadmap','100+ practice questions','Placement probability predictor'].map(f => (
              <div key={f} style={{ display:'flex', gap:8, alignItems:'center', marginBottom:8, fontSize:13, color:'var(--text2)' }}>
                <span style={{ color:'var(--emerald)', fontWeight:700 }}>✓</span> {f}
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="auth-right">
        <div className="auth-form">
          <div style={{ marginBottom:32 }}>
            <h2 className="auth-title">Create account</h2>
            <p className="auth-subtitle">Free forever — no credit card needed</p>
          </div>

          {error && <div className="alert alert-error" style={{ marginBottom:20 }}>⚠️ {error}</div>}

          <form onSubmit={handleSubmit}>
            <div className="form-group" style={{ marginBottom:16 }}>
              <label className="form-label">Full Name</label>
              <input className="form-input" type="text" placeholder="Your full name"
                value={form.name} onChange={e => setForm({...form, name: e.target.value})} required />
            </div>
            <div className="form-group" style={{ marginBottom:16 }}>
              <label className="form-label">Email Address</label>
              <input className="form-input" type="email" placeholder="you@example.com"
                value={form.email} onChange={e => setForm({...form, email: e.target.value})} required />
            </div>
            <div className="form-group" style={{ marginBottom:26 }}>
              <label className="form-label">Password</label>
              <input className="form-input" type="password" placeholder="Min. 6 characters"
                value={form.password} onChange={e => setForm({...form, password: e.target.value})} required minLength={6} />
            </div>

            <button className="btn btn-primary btn-lg" type="submit" disabled={loading} style={{ width:'100%', marginBottom:20 }}>
              {loading ? <><div className="spinner" style={{width:16,height:16,borderWidth:2}} /> Creating account...</> : 'Create Free Account →'}
            </button>
          </form>

          <p style={{ textAlign:'center', fontSize:13.5, color:'var(--text2)' }}>
            Already have an account?{' '}
            <Link to="/login" style={{ color:'var(--indigo2)', fontWeight:600, textDecoration:'none' }}>Sign in</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
